import {render, RenderPosition} from '../render.js';
import FiltersView from '../view/filters-view.js';
import SortView from '../view/sort-view.js';
import TripListView from '../view/trip-list-view.js';
import TripPointView from '../view/trip-point-view.js';
import EditPointView from '../view/edit-point-view.js';
import NewPointView from '../view/new-point-view.js';

export default class TripPresenter {
  #filtersContainer = null;
  #tripEventsContainer = null;

  constructor({filtersContainer, tripEventsContainer}) {
    this.#filtersContainer = filtersContainer;
    this.#tripEventsContainer = tripEventsContainer;
  }

  init() {
    render(new FiltersView(), this.#filtersContainer);
    render(new SortView(), this.#tripEventsContainer);

    const tripListComponent = new TripListView();
    render(tripListComponent, this.#tripEventsContainer);

    render(new EditPointView(), tripListComponent.getElement(), RenderPosition.AFTERBEGIN);
    render(new TripPointView(), tripListComponent.getElement());
    render(new TripPointView(), tripListComponent.getElement());
    render(new TripPointView(), tripListComponent.getElement());

    render(new NewPointView(), tripListComponent.getElement(), RenderPosition.BEFOREEND);
  }
}
